// Approximated code with 4-bit quantization
#define TEMP_MIN_ADC 0
#define TEMP_MAX_ADC 4095
uint8_t temp_readings_4bit[50];  // 50 bytes (2 readings per byte)

void store_temp_4bit(int index, uint16_t adc_val) {
    uint8_t quantized = (adc_val * 15) / TEMP_MAX_ADC;
    if(index % 2 == 0) {
        temp_readings_4bit[index/2] = (quantized << 4);
    } else {
        temp_readings_4bit[index/2] |= quantized;
    }
}

uint16_t read_temp_4bit(int index) {
    uint8_t quantized = (index % 2 == 0) ? 
        (temp_readings_4bit[index/2] >> 4) : 
        (temp_readings_4bit[index/2] & 0x0F);
    return (quantized * TEMP_MAX_ADC) / 15;
}
